mapper.select:
SELECT * FROM score

    AND student_id = #{studentId}
    AND paper_id = #{paperId}
    AND status = #{status}

mapper.update:
UPDATE score

    total_score = #{totalScore},
    status = #{status},
    submit_time = #{submitTime}

WHERE id = #{id}

mapper.select:
SELECT s.id as scoreId, s.student_id as studentId, s.paper_id as paperId, s.total_score as totalScore, s.status, s.submit_time as submitTime, stu.name as studentName, tp.name as paperName, c.id as courseId, c.name as courseName FROM score s LEFT JOIN student stu ON s.student_id = stu.id LEFT JOIN test_paper tp ON s.paper_id = tp.id LEFT JOIN course c ON tp.course_id = c.id WHERE tp.teacher_id = #{teacherId}
AND tp.course_id = #{courseId}
ORDER BY s.submit_time DESC

SELECT COUNT(*)
FROM score s
LEFT JOIN test_paper tp ON s.paper_id = tp.id
WHERE tp.teacher_id = #{teacherId}

    AND tp.course_id = #{courseId}
